### 2C. Enrichment Context

```typescript
/**
 * The context available when enriching a tool list.
 * Assembled from the scoring engine, policy engine, and upstream tool definitions.
 */
export interface EnrichmentContext {
  /** Customer identifier for tenant isolation. */
  customerId: string;

  /** The task/context type the agent is working on (e.g. "build_failed"). */
