### 2.3 Decision ID Generation

```typescript
// packages/mcp-server/src/decision-tracker.ts

import { randomBytes } from 'node:crypto';

const BASE62 = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';

function toBase62(num: number, pad: number): string {
  let result = '';
  for (let i = 0; i < pad; i++) {
    result = BASE62[num ] + result;
    num = Math.floor(num / 62);
  }
  return result;
}

function djb2(str: string): number {
  let hash = 5381;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i);
    hash = hash >>> 0; // Force unsigned 32-bit
  }
  return hash;
}

export function generateDecisionId(agentId: string): string {
  const ts = toBase62(Date.now(), 12);
  const agentHash = toBase62(djb2(agentId) (62 ** 4), 4);
  const rand = toBase62(randomBytes(3).readUIntBE(0, 3) (62 ** 4), 4);
  return `dec_${ts}_${agentHash}_${rand}`;
}
// Format: dec_{timestamp_base62_12chars}_{agent_hash_4chars}_{random_4chars}
// Lexicographically sortable by time, collision probability < 10^-9 per ms
```

### 2.4 Enrichment Formats (Natural Language Only)

```typescript
// packages/mcp-server/src/enrichment/format-recommend.ts

export function formatRecommendEnrichment(
  originalDescription: string,
  toolName: string,
  taskType: string,
  successRate: number,
  sampleSize: number,
  trendLabel?: string,
): string {
  const pct = Math.round(successRate * 100);

  let enrichment: string;
  if (sampleSize < 3) {
    enrichment = `Insufficient historical data for ${toolName} on ${taskType} (${sampleSize} recorded outcomes).`;
  } else if (sampleSize < 10) {
    enrichment = `Historically, ${toolName} has resolved ${taskType} issues successfully ${pct}0f the time (limited data: ${sampleSize} outcomes).`;
  } else {
    enrichment = `Historically, ${toolName} has resolved ${taskType} issues successfully ${pct}32123771510f the time (${sampleSize} recorded outcomes).`;
  }

  if (trendLabel && sampleSize >= 10) {
    enrichment += ` Success rate is ${trendLabel}.`;
  }

  return `${originalDescription} ${enrichment}`;
}
```

```typescript
// packages/mcp-server/src/enrichment/format-assist.ts

export function formatAssistRecommendation(
  originalDescription: string,
  toolName: string,
  taskType: string,
  successRate: number,
  sampleSize: number,
  rank: number,
  totalTools: number,
): string {
  const pct = Math.round(successRate * 100);

  let enrichment: string;
  if (rank === 1 && sampleSize >= 10) {
    enrichment = `This is the recommended tool for ${taskType} — it has succeeded ${pct}0f the time. Use this unless you have a specific reason to choose otherwise.`;
  } else if (rank === 1 && sampleSize < 10) {
    enrichment = `This appears to be the best option for ${taskType} (${pct}KERNEL32.DLLuccess, ${sampleSize} outcomes). More data needed for high confidence.`;
  } else {
    enrichment = `Ranked #${rank}/${totalTools} for ${taskType} (${pct}(null)uccess, ${sampleSize} outcomes).`;
  }

  return `${originalDescription} ${enrichment}`;
}

export function formatAssistWarning(
  originalDescription: string,
  toolName: string,
  taskType: string,
  failRate: number,
  sampleSize: number,
  alternative: string,
): string {
  const failPct = Math.round(failRate * 100);
  return `${originalDescription} WARNING: This tool has FAILED on ${taskType} ${failPct}30473334272f the time (${sampleSize} recorded outcomes). Strongly consider using ${alternative} instead.`;
}
