      entry.healthy = false;
      entry.lastCheck = Date.now();
      entry.lastError = err instanceof Error ? err.message : String(err);
      recordUpstreamFailure(this.state, server.name);
      log.warn('Upstream health check failed', {
        name: server.name,
        error: entry.lastError,
      });
    }
  }
}

